<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Models\Employee; use App\Models\Payroll\EmployeeSalaryProfile; use App\Models\Payroll\PayrollRun; use Illuminate\View\View; class PayrollDashboardController extends Controller{public function __invoke():View{return view('payroll.dashboard',['title'=>'Payroll Pegawai','profiled'=>EmployeeSalaryProfile::distinct('employee_id')->count('employee_id'),'unprofiled'=>Employee::where('is_active',true)->whereDoesntHave('salaryProfiles')->count(),'waiting'=>PayrollRun::where('status','submitted')->count(),'revision'=>PayrollRun::where('status','revision')->count(),'lastRun'=>PayrollRun::latest()->first()]);}}
